```javascript
import { UserService } from '@userservice/sdk';

const client = new UserService({ apiKey: 'your-key' });
const users = await client.users.list({ page: 1, perPage: 10 });
users.forEach(u => console.log(`${u.name}: ${u.email}`));
```

